dtsPropsFor.Button:
/** Visual style. Defaults to "secondary". */
variant?: "primary" | "secondary" | "ghost" | "danger";
/** Control height/padding. Defaults to "md". */
size?: "sm" | "md" | "lg";
children?: React.ReactNode;
className?: string;
disabled?: boolean;
type?: "button" | "submit" | "reset";
onClick?: React.MouseEventHandler<HTMLButtonElement>;
title?: string;
/* Also accepts every native <button> HTML attribute. */

dtsPropsFor.ProjectCard:
/** The project to display; the card links to /editor/<id>. */
project: {
  id: string;
  title: string;
  cover_asset?: string;
  created_at: string;
  updated_at: string;
};

dtsPropsFor.ModelPill:
/** Which catalog to show. */
kind: "image" | "llm";
/** For kind="image": scopes the list + selection to a generation mode. Defaults to "txt2img". */
mode?: "txt2img" | "img2img" | "inpaint" | "edit" | "controlnet" | "reference" | "video" | "figure";
/** Popover direction. Defaults to "bottom". */
placement?: "top" | "bottom";
/** Allow selecting models that aren't ready (no API key / not downloaded). */
allowNotReady?: boolean;

dtsPropsFor.ModelPillRow:
className?: string;
/** Scopes the image pill to a generation mode. */
mode?: "txt2img" | "img2img" | "inpaint" | "edit" | "controlnet" | "reference" | "video" | "figure";
/** Popover direction. Defaults to "bottom". */
placement?: "top" | "bottom";
